examples.source:
.hero {
  background-image: url('https://picsum.photos/id/1015/400/150');
  background-repeat: no-repeat;
  height: 150px;
  color: white;
  padding: 10px;
}

.banner {
  background-image: url('https://picsum.photos/id/1018/600/300');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  height: 140px;
}

.compact {
  background: #1e293b url('https://picsum.photos/id/1025/400/200') no-repeat center / cover;
  color: white;
  height: 120px;
  padding: 10px;
}
